```class Solution {
public:
    bool canConstruct(string s, int k) {
        int count[26] = {0}; // count array to store character counts
        int result = true;
        for (char c : s) {
            count[c - 'a']++;
            if (count[c - 'a'] > k) {
                result = false;
                break;
            }
        }
        for (int i = 0; i < s.length(); i++) {
            if (count[s[i] - 'a'] == 0) {
                result = false;
                break;
            }
            count[s[i] - 'a']--;
        }
        return result;
    }
};
```

